import { Component, inject, signal, computed } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterModule } from '@angular/router';
import { FormsModule } from '@angular/forms';
import { toSignal } from '@angular/core/rxjs-interop';
import { Subject, debounceTime, startWith, catchError, of } from 'rxjs';

import { AppStoreService } from '../../services/app-store.service';
import { AppInstallationService } from '../../services/app-installation.service';
import { AppDefinition } from '../../models/app-store.models';
import { AuthDataService } from '../../../../core/services/auth-data.service';

import { ButtonModule } from 'primeng/button';
import { InputTextModule } from 'primeng/inputtext';
import { SelectModule } from 'primeng/select';
import { TagModule } from 'primeng/tag';
import { RatingModule } from 'primeng/rating';
import { IconFieldModule } from 'primeng/iconfield';
import { InputIconModule } from 'primeng/inputicon';
import { CardModule } from 'primeng/card';
import { TooltipModule } from 'primeng/tooltip';

@Component({
  selector: 'app-app-marketplace',
  imports: [
    CommonModule,
    RouterModule,
    FormsModule,
    ButtonModule,
    InputTextModule,
    SelectModule,
    TagModule,
    RatingModule,
    IconFieldModule,
    InputIconModule,
    CardModule,
    TooltipModule,
  ],
  templateUrl: './app-marketplace.component.html',
  styleUrls: ['./app-marketplace.component.scss'],
})
export class AppMarketplaceComponent {
  private readonly appStoreService = inject(AppStoreService);
  private readonly appInstallationService = inject(AppInstallationService);
  private readonly authDataService = inject(AuthDataService);

  // State Signals
  readonly isLoading = signal(true);
  readonly error = signal<string | null>(null);
  readonly categoryFilter = signal('All');
  readonly statusFilter = signal<'ALL' | 'INSTALLED' | 'AVAILABLE'>('ALL');
  readonly sortOrder = signal('popular');

  // Static Data
  readonly categories = [
    'All',
    'Fleet Management',
    'Safety',
    'Maintenance',
    'Reporting',
  ];

  readonly statusOptions = [
    { label: 'All Apps', value: 'ALL' },
    { label: 'Installed', value: 'INSTALLED' },
    { label: 'Available', value: 'AVAILABLE' },
  ];

  readonly sortOptions = [
    { label: 'Most Popular', value: 'popular' },
    { label: 'Newest Arrivals', value: 'newest' },
    { label: 'Highest Rated', value: 'rating' },
  ];

  private readonly searchInput$ = new Subject<string>();
  private readonly searchQuery$ = this.searchInput$.pipe(
    debounceTime(250),
    startWith(''),
  );
  readonly searchQuery = toSignal(this.searchQuery$, { initialValue: '' });

  // Data Signals
  private readonly rawApps = toSignal(
    this.appStoreService.getApps().pipe(
      catchError(() => {
        this.error.set('Unable to load apps. Please try again.');
        return of([] as AppDefinition[]);
      }),
    ),
    { initialValue: [] as AppDefinition[] },
  );

  private readonly userInstallations = toSignal(
    this.appInstallationService
      .getInstallations({
        owner: this.authDataService.getUserProfile()?.id,
      })
      .pipe(catchError(() => of([]))),
    { initialValue: [] },
  );

  // Computed Signal for Filtered & Sorted Apps
  readonly apps = computed(() => {
    const apps = this.rawApps();
    const installations = this.userInstallations();
    const query = (this.searchQuery() || '').toLowerCase();
    const category = this.categoryFilter();
    const status = this.statusFilter();
    const sort = this.sortOrder();

    const installedAppIds = new Set(
      installations.map((i: { appId: string }) => i.appId),
    );

    const enhancedApps = apps.map((app) => ({
      ...app,
      isInstalled: installedAppIds.has(app.id),
    }));

    const filtered = enhancedApps.filter((app) => {
      const matchesSearch =
        app.name.toLowerCase().includes(query) ||
        app.shortDescription.toLowerCase().includes(query);
      const matchesCategory =
        category === 'All' || app.categories.includes(category);
      const matchesStatus =
        status === 'ALL' ||
        (status === 'INSTALLED' && app.isInstalled) ||
        (status === 'AVAILABLE' && !app.isInstalled);

      return matchesSearch && matchesCategory && matchesStatus;
    });

    // Update loading state when data is processed
    if (this.isLoading() && apps.length > 0) {
      setTimeout(() => this.isLoading.set(false));
    }

    return filtered.sort((a, b) => {
      if (sort === 'popular') return b.installCount - a.installCount;
      if (sort === 'newest')
        return (
          new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime()
        );
      if (sort === 'rating') return b.averageRating - a.averageRating;
      return 0;
    });
  });

  readonly isAdmin = this.authDataService.isSuperAdmin();

  onSearch(query: string): void {
    this.searchInput$.next(query);
  }

  onCategorySelect(category: string): void {
    this.categoryFilter.set(category);
  }

  onStatusFilterChange(status: string): void {
    this.statusFilter.set(status as 'ALL' | 'INSTALLED' | 'AVAILABLE');
  }

  onSortChange(sort: string): void {
    this.sortOrder.set(sort);
  }

  statusSeverity(
    status: AppDefinition['status'],
  ): 'success' | 'info' | 'warn' | 'danger' | 'secondary' {
    if (status === 'APPROVED') return 'success';
    if (status === 'PENDING_REVIEW') return 'warn';
    if (status === 'DRAFT') return 'secondary';
    if (status === 'SUSPENDED') return 'danger';
    return 'info';
  }

  statusLabel(status: AppDefinition['status']): string {
    return status
      .toLowerCase()
      .split('_')
      .map((part) => part[0].toUpperCase() + part.slice(1))
      .join(' ');
  }
}
