import { Injectable, inject } from '@angular/core';
import { HttpClient, HttpParams } from '@angular/common/http';
import { Observable } from 'rxjs';
import { map } from 'rxjs/operators';
import {
  AppInstallationApiResponse,
  AppInstallationListApiResponse,
  InstallAppRequest,
  UpdateAppConfigurationRequest,
  InstallationListQueryParams,
} from '../models/api/app-store-api.models';
import { ApiUrlService } from '../../../core/services/api-url.service';

/**
 * Frontend model for app installation
 */
export interface AppInstallation {
  id: string;
  ownerId: string;
  appId: string;
  appName: string;
  isEnabled: boolean;
  configuration: Record<string, unknown>;
  createdAt: string;
  updatedAt: string;
}

/**
 * Service for managing app installations
 */
@Injectable({
  providedIn: 'root',
})
export class AppInstallationService {
  private readonly http = inject(HttpClient);
  private readonly apiUrlService = inject(ApiUrlService);
  private readonly baseUrl: string;

  constructor() {
    this.baseUrl = `${this.apiUrlService.getCurrentApiUrl()}/appstore/installations`;
  }

  /**
   * Get all app installations for a user/organization
   * @param params Query parameters for filtering
   */
  getInstallations(
    params?: InstallationListQueryParams,
  ): Observable<AppInstallation[]> {
    let httpParams = new HttpParams();

    if (params) {
      if (params.owner !== undefined) {
        httpParams = httpParams.set('owner', params.owner);
      }
      if (params.offset !== undefined) {
        httpParams = httpParams.set('offset', params.offset.toString());
      }
      if (params.limit !== undefined) {
        httpParams = httpParams.set('limit', params.limit.toString());
      }
      if (params.sort !== undefined) {
        httpParams = httpParams.set('sort', params.sort);
      }
      if (params.filter !== undefined) {
        httpParams = httpParams.set('filter', params.filter);
      }
    }

    return this.http
      .get<AppInstallationListApiResponse>(this.baseUrl, {
        params: httpParams,
      })
      .pipe(
        map((response) => response.items.map((item) => this.mapFromApi(item))),
      );
  }

  /**
   * Get a specific installation by ID
   * @param id Installation ID
   * @param owner Optional owner filter
   */
  getInstallation(
    id: string,
    owner?: string,
  ): Observable<AppInstallation | null> {
    let httpParams = new HttpParams();
    if (owner !== undefined) {
      httpParams = httpParams.set('owner', owner);
    }

    return this.http
      .get<AppInstallationApiResponse>(`${this.baseUrl}/${id}`, {
        params: httpParams,
      })
      .pipe(map((response) => this.mapFromApi(response)));
  }

  /**
   * Install an app for a user/organization
   * @param appId The app to install
   * @param ownerId The owner (user/org) installing the app
   * @param configuration Optional initial configuration
   */
  installApp(
    appId: string,
    ownerId: string,
    configuration?: Record<string, unknown>,
  ): Observable<AppInstallation> {
    const request: InstallAppRequest = {
      appId,
      ownerId,
      configuration,
    };

    return this.http
      .post<AppInstallationApiResponse>(this.baseUrl, request)
      .pipe(map((response) => this.mapFromApi(response)));
  }

  /**
   * Uninstall an app
   * @param id Installation ID
   * @param owner Optional owner filter
   */
  uninstallApp(id: string, owner?: string): Observable<void> {
    let httpParams = new HttpParams();
    if (owner !== undefined) {
      httpParams = httpParams.set('owner', owner);
    }

    return this.http.delete<void>(`${this.baseUrl}/${id}`, {
      params: httpParams,
    });
  }

  /**
   * Update app configuration
   * @param id Installation ID
   * @param ownerId Owner ID
   * @param configuration New configuration
   */
  updateConfiguration(
    id: string,
    ownerId: string,
    configuration: Record<string, unknown>,
  ): Observable<AppInstallation> {
    const request: UpdateAppConfigurationRequest = {
      id,
      ownerId,
      configuration,
    };

    return this.http
      .patch<AppInstallationApiResponse>(
        `${this.baseUrl}/${id}/config`,
        request,
      )
      .pipe(map((response) => this.mapFromApi(response)));
  }

  /**
   * Maps API response to frontend model
   */
  private mapFromApi(apiResponse: AppInstallationApiResponse): AppInstallation {
    return {
      id: apiResponse.id,
      ownerId: apiResponse.ownerId,
      appId: apiResponse.appId,
      appName: apiResponse.appName,
      isEnabled: apiResponse.isEnabled,
      configuration: apiResponse.configuration,
      createdAt: apiResponse.createdDate,
      updatedAt: apiResponse.updatedDate,
    };
  }
}
